257‚Üí          </div>
258‚Üí
259‚Üí          <div style={{
260‚Üí            maxHeight: showReasons ? '800px' : '0',
261‚Üí            overflow: 'hidden',
262‚Üí            transition: 'max-height 0.4s ease, opacity 0.3s ease',
263‚Üí            opacity: showReasons ? 1 : 0,
264‚Üí          }}>
**265‚Üí            {/* Yo'naltirish removed from call form - now shown only when IN_PROGRESS */}
266‚Üí            <div style={{
267‚Üí              display: 'flex', flexWrap: 'wrap', gap: '8px', marginTop: '8px',
268‚Üí              padding: '12px', background: 'rgba(0,0,0,0.2)', borderRadius: '12px'
